    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "quote_currency": "krw",
        //         "target_currency": "btc",
        //         "timestamp": 1701073357818,
        //         "high": "50543000.0",
        //         "low": "49945000.0",
        //         "first": "50487000.0",
        //         "last": "50062000.0",
        //         "quote_volume": "11349804285.3859",
        //         "target_volume": "226.07268994",
        //         "best_asks": [
        //             {
        //                 "price": "50081000.0",
        //                 "qty": "0.18471358"
        //             }
        //         ],
        //         "best_bids": [
        //             {
        //                 "price": "50062000.0",
        //                 "qty": "0.04213455"
        //             }
        //         ],
        //         "id": "1701073357818001"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(ticker, "timestamp");
        Object last = this.safeString(ticker, "last");
        Object asks = this.safeList(ticker, "best_asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object bids = this.safeList(ticker, "best_bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object baseId = this.safeString(ticker, "target_currency");
        Object quoteId = this.safeString(ticker, "quote_currency");
        Object base = this.safeCurrencyCode(baseId);
        Object quote = this.safeCurrencyCode(quoteId);
        final Object finalBase = base;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", Helpers.add(Helpers.add(finalBase, "/"), quote) );
            put( "timestamp", timestamp );
            put( "datetime", CoinoneCore.this.iso8601(timestamp) );
            put( "high", CoinoneCore.this.safeString(ticker, "high") );
            put( "low", CoinoneCore.this.safeString(ticker, "low") );
            put( "bid", CoinoneCore.this.safeString(bids, "price") );
            put( "bidVolume", CoinoneCore.this.safeString(bids, "qty") );
            put( "ask", CoinoneCore.this.safeString(asks, "price") );
            put( "askVolume", CoinoneCore.this.safeString(asks, "qty") );
            put( "vwap", null );
            put( "open", CoinoneCore.this.safeString(ticker, "first") );
            put( "close", last );
            put( "last", last );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", CoinoneCore.this.safeString(ticker, "target_volume") );
            put( "quoteVolume", CoinoneCore.this.safeString(ticker, "quote_volume") );
            put( "info", ticker );
        }}, market);
    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "id": "1701075265708001",
        //         "timestamp": 1701075265708,
        //         "price": "50020000",
        //         "qty": "0.00155177",
        //         "is_seller_maker": false
        //     }
        //
        // fetchMyTrades (private)
        //
        //     {
        //         "timestamp": "1416561032",
        //         "price": "419000.0",
        //         "type": "bid",
        //         "qty": "0.001",
        //         "feeRate": "-0.0015",
        //         "fee": "-0.0000015",
        //         "orderId": "E84A1AC2-8088-4FA0-B093-A3BCDB9B3C85"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(trade, "timestamp");
        market = this.safeMarket(null, market);
        Object isSellerMaker = this.safeBool(trade, "is_seller_maker");
        Object side = null;
        if (Helpers.isTrue(!Helpers.isEqual(isSellerMaker, null)))
        {
            side = ((Helpers.isTrue(isSellerMaker))) ? "sell" : "buy";
        }
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.safeString(trade, "qty");
        Object orderId = this.safeString(trade, "orderId");
        Object feeCostString = this.safeString(trade, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            feeCostString = Precise.stringAbs(feeCostString);
            Object feeRateString = this.safeString(trade, "feeRate");
            feeRateString = Precise.stringAbs(feeRateString);
            Object feeCurrencyCode = ((Helpers.isTrue((Helpers.isEqual(side, "sell"))))) ? Helpers.GetValue(market, "quote") : Helpers.GetValue(market, "base");
            final Object finalFeeCostString = feeCostString;
            final Object finalFeeRateString = feeRateString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
                put( "rate", finalFeeRateString );
            }};
        }
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", CoinoneCore.this.safeString(trade, "id") );
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", CoinoneCore.this.iso8601(timestamp) );
            put( "order", orderId );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

    /**
     * @method
     * @name coinone#fetchTrades
     * @description get the list of most recent trades for a particular symbol
     * @see https://docs.coinone.co.kr/v1.0/reference/recent-completed-orders
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "quote_currency", Helpers.GetValue(market, "quote") );
                put( "target_currency", Helpers.GetValue(market, "base") );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "size", Helpers.mathMin(limit, 200));
            }
            Object response = (this.v2PublicGetTradesQuoteCurrencyTargetCurrency(this.extend(request, parameters))).join();
            //
            //     {
            //         "result": "success",
            //         "error_code": "0",
            //         "server_time": 1701075315771,
            //         "quote_currency": "KRW",
            //         "target_currency": "BTC",
            //         "transactions": [
            //             {
            //                 "id": "1701075265708001",
            //                 "timestamp": 1701075265708,
            //                 "price": "50020000",
            //                 "qty": "0.00155177",
            //                 "is_seller_maker": false
            //             }
            //         ]
            //     }
            //
            Object data = this.safeList(response, "transactions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            return this.parseTrades(data, market, since, limit);
        });

    }

    /**
     * @method
     * @name coinone#createOrder
     * @description create a trade order
     * @see https://doc.coinone.co.kr/#tag/Order-V2/operation/v2_order_limit_buy
     * @see https://doc.coinone.co.kr/#tag/Order-V2/operation/v2_order_limit_sell
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type must be 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(!Helpers.isEqual(type, "limit")))
            {
                throw new ExchangeError((String)Helpers.add(this.id, " createOrder() allows limit orders only")) ;
            }
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "price", price );
                put( "currency", Helpers.GetValue(market, "id") );
                put( "qty", amount );
            }};
            Object method = Helpers.add(Helpers.add("privatePostOrder", this.capitalize(type)), this.capitalize(((String)side)));
            Object response = ((java.util.concurrent.CompletableFuture<Object>)Helpers.callDynamically(this, method, new Object[] { this.extend(request, parameters) })).join();
            //
            //     {
            //         "result": "success",
            //         "errorCode": "0",
            //         "orderId": "8a82c561-40b4-4cb3-9bc0-9ac9ffc1d63b"
            //     }
            //
            return this.parseOrder(response, market);
        });

    }

